    private fun normalize(value: String): String =
        value
            .lowercase()
            .trim()
            .replace("\u200f", "")
            .replace("\u200e", "")
            .replace("\u00a0", " ")
            .replace("–", "-")
            .replace("—", "-")
            .replace("־", "-")
            .replace("/", " ")
            .replace("?", " ")
            .replace("!", " ")
            .replace(",", " ")
            .replace(".", " ")
            .replace(Regex("\\s+"), " ")
            .trim()

    private fun cleanQuestion(value: String): String {
        var t = normalize(value)

        val prefixes = listOf(
            "תן הסבר על", "תן הסבר ל", "תני הסבר על", "תני הסבר ל",
            "תסביר לי את", "תסביר לי", "תסביר את", "תסביר",
            "תסבירי לי את", "תסבירי לי", "תסבירי את", "תסבירי",
            "איך עושים את", "איך עושים", "איך מבצעים את", "איך מבצעים",
            "מה זה", "מה ההסבר של", "הסבר על", "הסבר ל",
            "explain the", "explain", "how to do the", "how to do", "what is"
        )

        prefixes.forEach { p ->
            if (t.startsWith(p)) {
                t = t.removePrefix(p).trim()
            }
        }

        return t
            .removePrefix("את ")
            .replace(Regex("\\s+"), " ")
            .trim()
    }

    private fun queryAliases(q: String): Set<String> {
        val base = cleanQuestion(q)
        val set = linkedSetOf(base)

        fun addIfContains(token: String, mapped: String) {
            if (base.contains(token)) set.add(mapped)
        }

        addIfContains("מגל", "בעיטת מגל")
        addIfContains("סטירה", "בעיטת סטירה")
        addIfContains("דקירה", "הגנה נגד דקירה")
        addIfContains("מזרחית", "הגנה נגד דקירה מזרחית")
        addIfContains("מערבית", "הגנה נגד דקירה מערבית")
        addIfContains("חניקה", "שחרור מחניקה")
        addIfContains("חביקה", "שחרור מחביקה")
        addIfContains("תפיסת יד", "שחרור מתפיסת יד")
        addIfContains("אגרוף", "אגרוף")
        addIfContains("מרפק", "מכת מרפק")
        addIfContains("ברך", "בעיטת ברך")

        addIfContains("roundhouse", "בעיטת מגל")
        addIfContains("slap", "בעיטת סטירה")
        addIfContains("knife", "הגנה נגד דקירה")
        addIfContains("stab", "הגנה נגד דקירה")
        addIfContains("choke", "שחרור מחניקה")
        addIfContains("punch", "אגרוף")
        addIfContains("kick", "בעיטה")
        addIfContains("elbow", "מכת מרפק")
        addIfContains("knee", "בעיטת ברך")

        return set.filter { it.isNotBlank() }.toSet()
    }

    private fun scoreTitle(query: String, title: String): Int {
        val q = normalize(query)
        val t = normalize(title)
        if (q.isBlank() || t.isBlank()) return 0

        var score = 0

        if (q == t) score += 1000
        if (t.startsWith(q)) score += 260
        if (t.contains(q)) score += 220
        if (q.contains(t)) score += 180

        val qWords = q.split(" ").filter { it.length >= 2 }
        val tWords = t.split(" ").filter { it.length >= 2 }.toSet()

        val hits = qWords.count { it in tWords || t.contains(it) }
        score += hits * 45

        if (qWords.isNotEmpty() && hits == qWords.size) score += 120

        score -= kotlin.math.abs(t.length - q.length).coerceAtMost(80)

        return score
    }

    fun findBest(
        query: String,
        preferredBelt: Belt? = null,
        minScore: Int = 70
    ): Match? {
        val variants = queryAliases(query)
        if (variants.isEmpty()) return null

        val best = entries
            .asSequence()
            .map { entry ->
                val baseScore = variants.maxOf { variant -> scoreTitle(variant, entry.title) }
                val beltBoost = if (preferredBelt != null && preferredBelt == entry.belt) 35 else 0
                entry to (baseScore + beltBoost)
            }
            .filter { (_, score) -> score >= minScore }
            .sortedWith(
                compareByDescending<Pair<Entry, Int>> { it.second }
                    .thenBy { it.first.title.length }
            )
            .firstOrNull()
            ?: return null

        val explanation = Explanations.get(best.first.belt, best.first.title).trim()
        if (explanation.isBlank() || explanation.startsWith("הסבר מפורט על:")) return null

        return Match(
            belt = best.first.belt,
            title = best.first.title,
            explanation = explanation,
            score = best.second
        )
    }
